<template>
	<view>
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<slideCode v-if="slideCode[1].show" :session_id="session_id[1]" @close="slideCode[1].show = false"
			@success="$slideCode_success2(1, $event)"></slideCode>
		<view class="callback-container">
			<!-- <view v-if="!needBind">登录中</view> -->
			<view v-if="needBind" class="bind-box">
				<view class="main-wrap" v-show="activeWrap == 1">
					<view class="logo">
						<text>首次登录绑定</text>
					</view>
					<view class="btns">
						<view class="btn1" v-if="openRegInputMobile">
							<u-button type="error" @click="activeWrap =3">新用户，自动创建一个账号</u-button>
						</view>
						<view class="btn1" v-else-if="openRegNeedPid">
							<u-button type="error" @click="activeWrap = 4">新用户，自动创建一个账号</u-button>
						</view>
						<view class="btn1" v-else>
							<u-button type="error" @click="handelNewUser">新用户，自动创建一个账号</u-button>
							<!-- <text class="tip">初始登录和交易密码为123123</text> -->
						</view>
						<u-button type="info" @click="handelOldUser">老用户，立即绑定一个账号</u-button>
					</view>
				</view>
				<view class="user-wrap" v-show="activeWrap == 2">
					<view class="page-header" @click="goBack">
						<text class="iconfont icon-fanhuijiantou"></text>第三方登录账号绑定
					</view>
					<view class="user-form">
						<u-form :model="bindForm" ref="form" :rules="rules" label-width="80rpx">
							<u-form-item label="" prop="username" label-width="0">
								<u-input v-model="bindForm.username" placeholder="请输入账号" clearable />
							</u-form-item>
							<u-form-item label="" prop="password" label-width="0">
								<u-input v-model="bindForm.password" type="password" placeholder="请输入密码" clearable
									password-icon />
							</u-form-item>
							<u-form-item label="" label-width="0">
								<u-button type="primary" @click.native="onSubmit" style="width:100%">立即绑定</u-button>
							</u-form-item>
						</u-form>
					</view>
				</view>
				<view class="user-wrap" v-show="activeWrap == 3">
					<view class="page-header" @click="goBack">
						<text class="iconfont icon-fanhuijiantou"></text>第三方登录账号绑定
					</view>
					<view class="user-form">
						<u-form :model="createForm" ref="form2" :rules="rules2" label-width="80rpx">
							<u-form-item label="" prop="mobile" label-width="0">
								<u-input v-model="createForm.mobile" type="text" placeholder="请输入手机号" height="40" />
							</u-form-item>
							<u-form-item label="" prop="captcha" label-width="0">
								<u-input v-model="createForm.captcha" type="text" maxlength="6" placeholder="请输入验证码"
									height="40" />
								<view class="" :style="is_sendCode?'color:#c3c8d9;':'color:red;'" @click="sendCode(10)">
									<u-verification-code :seconds="seconds" ref="uCode" @start="codeStart"
										@end="codeEnd" @change="codeChange" start-text="获取验证码"
										change-text="X秒"></u-verification-code>
									<view class="">
										{{tips}}
									</view>
								</view>
							</u-form-item>
							<u-form-item label="" prop="pid" v-if="openRegNeedPid" label-width="0">
								<u-input v-model="createForm.pid" type="text" placeholder="上级编号" height="40" />
							</u-form-item>
							<u-form-item label="" label-width="0">
								<u-button type="primary" @click.native="handelNewUser"
									style="width:100%">立即创建</u-button>
							</u-form-item>
						</u-form>
					</view>
				</view>
				<view class="user-wrap" v-show="activeWrap == 4">
					<view class="page-header" @click="goBack">
						<text class="iconfont icon-fanhuijiantou"></text>第三方登录账号绑定
					</view>
					<view class="user-form">
						<u-form :model="createForm" ref="form2" :rules="rules2" label-width="80rpx">
							<u-form-item label="" prop="pid" label-width="0">
								<u-input v-model="createForm.pid" type="text" placeholder="上级编号" height="40" />
							</u-form-item>
							<u-form-item label="" label-width="0">
								<u-button type="primary" @click.native="handelNewUser"
									style="width:100%">立即创建</u-button>
							</u-form-item>
						</u-form>
					</view>
				</view>
			</view>
		</view>
		<regPay ref="regpay" @success="handelPaySuccess" />
	</view>
</template>

<script>
	import {
		mapGetters,
		mapMutations,
	} from 'vuex'
	import regPay from '@/components/reg-pay'
	import slideCode from '@/components/slideCode.vue'
	export default {
		components: {
			regPay,
			slideCode
		},
		data() {
			return {
				loginToken: '', // 网页授权登录
				openid: '', // 扫码登录：openid，type
				type: '',
				needBind: false,
				activeWrap: 1,
				createForm: {
					openid: '',
					type: '',
					pid: 0,
					mobile: '',
					captcha: '',
				},
				bindForm: {
					openid: '',
					type: '',
					username: '',
					password: '',
					pid: 0,
				},
				rules: {
					username: [{
						required: true,
						trigger: 'blur',
						message: '账号不能为空'
					}, ],
					password: [{
						required: true,
						trigger: 'blur',
						message: '密码不能为空'
					}, ],
				},
				rules2: {
					mobile: [{
						required: true,
						trigger: 'blur',
						message: '手机号码不能为空'
					}],
					captcha: [{
						required: true,
						trigger: 'blur',
						message: '短信验证码不能为空'
					}]
				},
				return_url: '/pages/index/index',
				openRegInputMobile: uni.getStorageSync('open_reg_input_mobile'),
				// openRegInputMobile: true,
				openRegNeedPid: false,
				slideCode: [{
					show: false
				}, {
					show: false
				}],
				session_id: [], //会自动生成的

				tips: '',
				seconds: 60,
				is_sendCode: false, //是否发送验证码
			};
		},
		onLoad(e) {
			this.$slideCode_init(0) //初始化图形滑块
			this.$slideCode_init(1) //初始化图形滑块

			if (!this.needBind) {
				uni.showLoading({
					mask: true,
					title: '登录中...'
				})
			}
			// console.log(this.openRegInputMobile);
			if (this.userinfo.token) {
				this.$util.on('/pages/index/index')
			} else {
				const {
					login_token,
					openid,
					type
				} = e
				this.loginToken = login_token

				this.openid = openid
				this.type = type
				if (this.loginToken) {
					this.$u.api.thirdLogin2({
						login_token: this.loginToken
					}).then(res => {


						let pid = uni.getStorageSync('pid')
						const {
							login_type,
							type,
							openid,
							token,
							userinfo,
							return_url
						} = res


						this.openRegNeedPid = res.open_reg_need_pid ? true : false;
						this.openRegInputMobile = res.open_reg_input_mobile ? true : false;

						if (return_url) {
							this.return_url = return_url;
						}
						if (login_type == 2) // 已经绑定用户，直接登录
						{
							this.needBind = false
							uni.hideLoading()

							userinfo.isLogin = true
							uni.setStorageSync('token', token)
							this.$u.vuex('token', token)
							this.$u.vuex('userinfo', userinfo)


							if (return_url) {

								this.$util.on(return_url)
							} else {

								this.$util.on(this.return_url)
							}

						} else if (login_type == 3) // 需要绑定用户
						{


							this.needBind = true
							uni.hideLoading()

							this.createForm = Object.assign({}, {
								openid,
								type,
								pid
							})
							this.bindForm = Object.assign(this.bindForm, {
								openid,
								type,
								pid
							})
						}
					}).catch(err => {
						uni.hideLoading()
					})
				}

			}



		},
		onShow() {
			if (this.userinfo.isLogin) {
				this.$util.on('/pages/index/index')
			}
		},
		onReady() {

		},
		methods: {
			codeChange(text) {
				this.tips = text;
			},
			//发送验证码
			sendCode() {

				if (!this.$u.test.mobile(this.createForm.mobile)) return this.$u.toast('请输入正确的手机号')

				this.slideCode[0].show = true; //滑块验证码


			},
			codeStart() {
				this.is_sendCode = true;
			},
			codeEnd() {
				this.is_sendCode = false;
			},
			canGetCode() {
				if (this.$refs.uCode.canGetCode) {
					// 模拟向后端请求验证码
					uni.showLoading({
						title: '正在获取验证码'
					})

					let data = {
						send_type: 10,
						mobile: this.createForm.mobile,
						session: this.session_id[0],
					}
					this.$u.api.sendCode(data).then(res => {
						uni.hideLoading();
						// 这里此提示会被this.start()方法中的提示覆盖
						this.$u.toast('验证码已发送');
						// 通知验证码组件内部开始倒计时
						this.$refs.uCode.start();
					}).catch((res) => {
						console.log(res);
						this.$u.toast('验证码已发送');
					})

				} else {
					this.$u.toast('倒计时结束后再发送');
				}
			},
			async handelNewUser() {
				const {
					reg_status,
					reg_data,
					token,
				} = await this.$u.api.toCreate(this.createForm)
				if (reg_status == 1) {
					this.$refs['regpay'].show({
						reg_code: reg_data.reg_code
					})
				} else {
					this.$util.msg('创建成功');
					//存储token
					uni.setStorageSync('token', token)
					this.$u.vuex('token', token)
					await this.getUserInfo()
					setTimeout(() => {
						this.$util.on(this.return_url)
					}, 1500)
				}
			},
			handelOldUser() {
				this.activeWrap = 2
				this.$refs['form'].setRules(this.rules)
			},
			goBack() {
				this.$refs['form'].resetFields();
				this.activeWrap = 1
			},
			onSubmit() {
				this.$refs['form'].validate(async (valid) => {
					if (valid) {
						this.slideCode[1].show = true
					} else {
						console.log('error submit!!')
						return false
					}
				})
			},
			getUserInfo() {
				return new Promise((resolve, reject) => {
					this.$u.api.userinfo().then(res => {
						let userinfo = res.userinfo
						userinfo.isLogin = true
						for (let key in userinfo) {
							this.$u.vuex('userinfo.' + key, userinfo[key]);
						}
						resolve()
					}).catch(e => {
						reject(e)
					})
				})
			},
			// 付费注册成功回调
			async handelPaySuccess({
				token
			}) {
				//存储token
				uni.setStorageSync('token', token)
				this.$u.vuex('token', token)
				await this.getUserInfo()
				setTimeout(() => {
					this.$util.on(this.return_url);
				}, 1500)
			},
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值

				this.canGetCode() //获取验证码			
			},
			async $slideCode_success2(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值

				const {
					token
				} = await this.$u.api.toBind(this.bindForm)

				uni.setStorageSync('token', token)
				this.$u.vuex('token', token)
				this.getUserInfo()
				// this.$router.replace({
				// 	path: '/'
				// })
				this.$util.msg('绑定成功');
				setTimeout(() => {
					this.$util.on(this.return_url)
				}, 1500)
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.callback-container {
		position: fixed;
		left: 0;
		top: 0;
		right: 0;
		bottom: 0;
		background: #f5f5f5;
		// background-image: url(../../assets/login_bg.png);
		background-size: cover;
		background-position: center;

		.bind-box {
			position: absolute;
			width: 600rpx;
			padding: 38rpx 30rpx;
			background: #fff;
			border-radius: 10rpx;
			top: 40%;
			left: 50%;
			border: 1px solid #F2F2F2;
			transform: translate(-50%, -50%);

			.main-wrap {
				height: 100%;
				display: flex;
				flex-direction: column;
				gap: 40rpx;

				.logo {
					display: flex;
					align-items: center;
					justify-content: space-between;
					border-bottom: 1px solid #DCDFE6;
					height: 80rpx;

					.logo-img {
						width: 200px;
					}

					text {
						font-size: 32rpx;
						color: #EA0808;
						font-weight: bold;
					}
				}

				.btns {
					display: flex;
					flex-direction: column;

					.btn1 {
						margin-bottom: 40rpx;
						display: flex;
						flex-direction: column;

						.tip {
							text-align: center;
							color: #EA0808;
						}
					}
				}
			}

			.user-wrap {
				.user-form {}
			}
		}
	}
</style>